import redis
import os
import json
import uuid
import time

class DistributedCacheService:
    def __init__(self, redis_nodes, default_ttl_seconds=3600):
        """
        Initializes the DistributedCacheService with a list of Redis nodes.
        It uses a Redis cluster client to handle multiple nodes.

        :param redis_nodes: A list of dictionaries, each containing 'host' and 'port' for a Redis node.
                            Example: [{'host': 'localhost', 'port': 6379}, {'host': 'localhost', 'port': 6380}]
        :param default_ttl_seconds: Default time-to-live for cache entries in seconds.
        """
        if not redis_nodes:
            raise ValueError("redis_nodes cannot be empty.")

        # For a true Redis cluster, use redis.RedisCluster.
        # For a list of standalone nodes (e.g., for sharding manually or just multiple single instances),
        # redis-py's Redis class can connect to a single node, and you'd manage distribution yourself.
        # Assuming a Redis Cluster for true distribution.
        # If it's just a list of standalone nodes, you might need a custom sharding logic.
        # For simplicity and common use case of "remote Redis cluster", we'll assume redis.RedisCluster.
        # If the user meant a list of standalone instances that *aren't* a cluster, the approach would differ
        # significantly (e.g., consistent hashing client).

        # Extracting startup nodes for redis-py RedisCluster
        startup_nodes = [
            redis.StrictRedis(host=node['host'], port=node['port'], decode_responses=True)
            for node in redis_nodes
        ]
        self.client = redis.RedisCluster(startup_nodes=startup_nodes, decode_responses=True)
        self.default_ttl = default_ttl_seconds
        print(f"Initialized Redis Cluster client with startup nodes: {redis_nodes}")

    def _serialize_data(self, data):
        """Serializes data to JSON string for storage in Redis."""
        return json.dumps(data)

    def _deserialize_data(self, data_str):
        """Deserializes data from JSON string stored in Redis."""
        if data_str is None:
            return None
        return json.loads(data_str)

    def set_session_token(self, user_id, session_token, ttl_seconds=None):
        """
        Stores a session token for a user.
        :param user_id: Identifier for the user.
        :param session_token: The session token string.
        :param ttl_seconds: Time-to-live for the session token in seconds. Defaults to default_ttl.
        :return: True if set successfully, False otherwise.
        """
        key = f"session:{user_id}"
        ttl = ttl_seconds if ttl_seconds is not None else self.default_ttl
        try:
            self.client.set(key, session_token, ex=ttl)
            print(f"Set session token for user {user_id} with TTL {ttl}s.")
            return True
        except redis.exceptions.RedisError as e:
            print(f"Error setting session token for user {user_id}: {e}")
            return False

    def get_session_token(self, user_id):
        """
        Retrieves a session token for a user.
        :param user_id: Identifier for the user.
        :return: The session token string or None if not found.
        """
        key = f"session:{user_id}"
        try:
            token = self.client.get(key)
            print(f"Retrieved session token for user {user_id}.")
            return token
        except redis.exceptions.RedisError as e:
            print(f"Error getting session token for user {user_id}: {e}")
            return None

    def delete_session_token(self, user_id):
        """
        Deletes a session token for a user.
        :param user_id: Identifier for the user.
        :return: True if deleted, False otherwise.
        """
        key = f"session:{user_id}"
        try:
            deleted_count = self.client.delete(key)
            if deleted_count > 0:
                print(f"Deleted session token for user {user_id}.")
                return True
            else:
                print(f"Session token for user {user_id} not found for deletion.")
                return False
        except redis.exceptions.RedisError as e:
            print(f"Error deleting session token for user {user_id}: {e}")
            return False

